          image: { src: "/images/blog/fr/technical-seo-sitemap-structure.svg", alt: "XML sitemap structure for large ecommerce catalogs showing sitemap index with separate product, category, blog, and pages sitemaps", caption: "Split sitemaps by page type to diagnose indexing issues faster and keep each file under 50,000 URLs." },
